#define int long long
int a,m;
string b;
int ol(int n){
	int res=n;
	for(int i=2;i*i<=n;i++){
		if(n%i==0){
			res=res/i*(i-1);
			while(n%i==0){
				n/=i;
			}
		}
	}
	if(n>1){
		res=res/n*(n-1);
	}
	return res;
}
int qpow(int a,int b,int p) {
	int res=1;
	a%=p;
	while (b) {
		if (b&1)res=res*a%p;
		a=a*a%p;
		b>>=1;
	}
	return res;
}
