void dj(int n,int s) {
	vector<string> a(n);
	priority_queue<pii,vector<pii>,greater<pii>> pq;
	vector<int> dis1(n+5,inf),dis2(n+5,inf);
	dis1[s]=0;
	pq.push({0,s});
	while(pq.size()) {
		int d=pq.top().x,u=pq.top().y;
		pq.pop();
		if(d>dis2[u]) {
			continue;
		}
		for(auto e:g[u]) {
			int v=e.x,w=e.y,ss=d+w;
			if(ss<dis1[v]) {
				dis2[v]=dis1[v];
				dis1[v]=ss;
				pq.push({dis1[v],v});
				pq.push({dis2[v],v});
			} else if(ss<dis2[v]&&ss>dis1[v]) {
				dis2[v]=ss;
				pq.push({dis2[v],v});
			}
		}
	}
	for(int i=0; i<dis2.size(); i++) {
		if(dis2[1+i]==inf) {
			cout<<dis2[i];
			return ;
		}
	}
}
