const int maxn=4e4+5;
int pr[maxn],cnt,ans=1,phi[maxn];
bool st[maxn];
int lala(int n) {
	phi[1]=1;
	for(int i=2; i<n; i++) {
		if(!st[i]) {
			pr[cnt++]=i;
			phi[i]=i-1;
		}
		for(int j=0; pr[j]<=n/i; j++) {
			int p=pr[j];
			st[i*p]=1;
			if(i%p==0) {
				phi[i*p]=phi[i]*p;
				break;
			}
			phi[i*p]=phi[i]*(p-1);
		}
		ans+=phi[i];
	}
	ans*=2;
	ans++;
	return ans;
}
