#include <bits/stdc++.h>
using namespace std;
const int ma=55;
int n,g[ma],maxn,sl,ans;
vector<int> v;

void dfs(int pos,int rest,int len,int cnt){
    if(rest==0){
        if(--cnt==0){
            ans=len;
            return;
        }
        for(int i=0;i<v.size();i++){
            if(g[v[i]]==0) continue;
            g[v[i]]--;
            dfs(i,len-v[i],len,cnt);
            if(ans!=-1) return;
            g[v[i]]++;
            break;
        }
        return;
    }
    for(int i=pos;i<v.size();i++){
        int l=v[i];
        if(g[l]==0||l>rest) continue;
        g[l]--;
        dfs(i,rest-l,len,cnt);
        if(ans!=-1) return;
        g[l]++;
