		cout<<-1<<"\n";
		return 0;
	}
	for(int i=1; i<=n; i++) {
		for(auto&j:v[i].e) {
			j.second+=v[i].h-v[j.first].h;
		}
	}
	for(int i=1; i<=n; i++) {
		dijkstra(i);
	}
	return 0;
}

