#include <bits/stdc++.h>
using namespace std;
const int maxn=100005;
long long arr[maxn];
long long tree[maxn*4];
long long lazy[maxn*4];
void push_up(int p) {
	tree[p]=tree[p<<1]+tree[p<<1|1];
}
void push_down(int p, int l, int r) {
	if (lazy[p]==0)return;
	int mid=(l+r)>>1;
	lazy[p<<1]+=lazy[p];
	tree[p<<1]+=lazy[p]*(mid-l+1);
	lazy[p<<1|1]+=lazy[p];
	tree[p<<1|1]+=lazy[p]*(r-mid);
	lazy[p]=0;
}
void build(int p,int l,int r) {
	lazy[p]=0;
	if(l==r) {
		tree[p]=arr[l];
		return;
	}

	int mid=(l+r)>>1;
	build(p<<1,l,mid);
	build(p<<1|1,mid+1,r);
	push_up(p);
}
void update(int p,int l,int r,int ql,int qr,long long k) {
	if(ql<=l&&r<=qr) {
		tree[p]+=k*(r-l+1);
		lazy[p]+=k;
		return;
	}
	push_down(p,l,r);
	int mid=(l+r)>>1;
	if(ql<=mid)update(p<<1,l,mid,ql,qr,k);
	if(qr>mid)update(p<<1|1,mid+1,r,ql,qr,k);
	push_up(p);
}
long long query(int p,int l,int r,int ql,int qr) {
	if(ql<=l&&r<=qr) {
		return tree[p];
	}
	push_down(p,l,r);

	int mid=(l+r)>>1;
	long long res=0;
	if(ql<=mid)res+=query(p<<1,l,mid,ql,qr);
	if(qr>mid)res+=query(p<<1|1,mid+1,r,ql,qr);

	return res;
}

int main() {
	int n,m;
	cin>>n>>m;
	for(int i=1; i<=n; i++) {
		cin>>arr[i];
	}
	build(1,1,n);
	while(m--) {
		int op;
		cin>>op;
		if(op==1) {
			int x,y;
			long long k;
			cin>>x>>y>>k;
			update(1,1,n,x,y,k);
		} else {
			int x,y;
			cin>>x>>y;
			cout<<query(1,1,n,x,y)<<"\n";
		}
	}
	return 0;
}

