const int mod=19260817;
int x,y;
void exgcd(int a,int b) {
	if(b==0) {
		x=1;
		y=0;
		return;
	}
	exgcd(b,a%b);
	int s=x;
	x=y;
	y=s-a/b*y;
}
int inv(int b, int p) {
	exgcd(b,mod);
