#include <iostream>
#include <vector>
#include <string>
using namespace std;

// 定义方向数组：上、左、下、右
const int dx[] = {-1, 0, 1, 0};
const int dy[] = {0, -1, 0, 1};

// DFS函数
bool dfs(vector<vector<int>>& maze, vector<vector<bool>>& visited, vector<pair<int, int>>& path, pair<int, int> start, pair<int, int> end) {
    int x = start.first, y = start.second;

    // 如果当前点是终点，输出路径
    if (start == end) {
        for (size_t i = 0; i < path.size(); ++i) {
            if (i != 0) cout << " -> ";
            cout << "(" << path[i].first << "," << path[i].second << ")";
        }
        cout << endl;
        return true;
    }

    // 标记当前点为已访问
    visited[x][y] = true;

    bool found = false;
    for (int i = 0; i < 4; ++i) { // 遍历四个方向
        int nx = x + dx[i], ny = y + dy[i];
        // 检查下一个点是否在迷宫范围内、是否可走、是否未访问
        if (nx >= 0 && nx < maze.size() && ny >= 0 && ny < maze[0].size() && maze[nx][ny] == 1 && !visited[nx][ny]) {
            path.push_back({nx, ny}); // 将下一个点加入路径
            if (dfs(maze, visited, path, {nx, ny}, end)) {
                found = true;
            }
            path.pop_back(); // 回溯，移除最后一个点
        }
    }

    // 回溯，标记当前点为未访问
    visited[x][y] = false;
    return found;
}

// 主函数
int main() {
    int m, n;
    cin >> m >> n;

    // 读取迷宫
    vector<vector<int>> maze(m, vector<int>(n));
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            cin >> maze[i][j];
        }
    }

    // 读取起始点和结束点
    pair<int, int> start, end;
    cin >> start.first >> start.second;
    cin >> end.first >> end.second;

    // 初始化访问标记数组和路径
    vector<vector<bool>> visited(m, vector<bool>(n, false));
    vector<pair<int, int>> path;
    path.push_back(start);

    // 调用DFS函数
    if (!dfs(maze, visited, path, start, end)) {
