	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int t,n,m,ans=0;
	cin>>t>>x;
	c1[0]=c2[0]=1;
	sx();
	while(t--) {
		cin>>n>>m;
		ans^=C(n,m);
	}
	cout<<ans;
	return 0;
}

