#include <bits/stdc++.h>
using namespace std;
const int maxn=15;
int m,n,ans,a[maxn][maxn],t[maxn],vis[maxn];
bool check() {
	fill(t,t+maxn+1,0);
	for(int i=1; i<=m; i++) {
		if(vis[i]) {
			for(int j=1; j<=a[i][0]; j++) {
				t[a[i][j]]=1;
			}
		}
	}
	for(int i=1; i<=n; i++) {
		if(t[i]==0) return 0;
	}
	return 1;
}
void dfs(int k) {
	if(k>m) {
		if(check()) {
			ans++;
		}
		return ;
	}
	vis[k]=1;
	dfs(k+1);
	vis[k]=0;
	dfs(k+1);
}
