#include<bits/stdc++.h>
using namespace std;
#define endl '\n'
#define int long long
const int maxn=1001;
int T,a,b,t,k,x,deep,res,l[maxn],ans[maxn],vis[maxn];
int gcd(int x,int y) {
	return y==0?x:gcd(y,x%y);
}
bool check() {
	for(int i=deep; i>=1; i--) {
		if(l[i]!=ans[i]) {
			return l[i]<ans[i];
		}
	}
	return 0;
}
void dfs(int i,int x,int y) {
	//当前正在填第i个分母  分数还剩 x / y
	int g=gcd(x,y);
	x/=g,y/=g;
	if(i>=deep) {
		l[i]=y;
		if(x==1 && y>l[i-1] && vis[y]!=t && (!res||check())) {	//合法&&最优
			res=1;
			copy(l+1,l+1+deep,ans+1);
		}
		return;
	}
	for(l[i]=max(y/x,l[i-1])+1; x/y <= (deep-i+1)*1/l[i] ; l[i]++) {
		if(vis[l[i]]!=t)	dfs(i+1,l[i]*x-y,y*l[i]);
	}
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>T;
	for(t=1; t<=T; t++) {
		cin>>a>>b>>k;
		while(k--) {
			cin>>x;
			vis[x]=t;
		}
		for(deep=0,res=0; !res; deep++) {//IDDFS
			dfs(1,a,b);
		}
		//Case 1: 2/3=1/2+1/6
		cout<<"Case "<<t<<": "<<a<<"/"<<b<<"=1/"<<ans[1];
		for(int i=2; i<=deep; i++) cout<<"+1/"<<ans[i];
		cout<<endl;
	}
	return 0;
}

