queue<int> q;
struct node{
	int to,nxt;
}e[maxn<<1];
void add(int a,int b,int p) {
	e[p]=(node) {
		b,fir[a]
	};
	fir[a]=p;
}
void bfs(int s,int* dis) {
	for(int i=1; i<=n; i++)dis[i]=INT_MAX;
	q.push(s);
	dis[s]=0;
	while(!q.empty()) {
		int x=q.front();
		q.pop();
		for(int i=fir[x]; i; i=e[i].nxt) {
			int h=e[i].to;
			if(dis[h]==INT_MAX) {
				q.push(h);
				dis[h]=dis[x]+1;
			}
		}
	}
}
