		day[i]=0;
	}
	long long kx=0,j=0;
	for(int i=1; i<=d; i++) {
		kx=kx>>1;
		while(kx<x) {
			j++;
			kx+=qq[j];
			day[j]=i;
			if(j>n) {
				return 0;
			}
		}
	}
