	while(l<=r) {
		mid=(l+r)>>1;
		if(!check(mid)) {
			r=mid-1;
		}
		if(check(mid)) {
			l=mid+1;
			ans=mid;
		}
	}
	cout<<ans<<"\n";
	for(int i=1; i<=n; i++) {
