int gl,n,m,a[maxn],l,r,ans;
bool vis[maxn];
bool cheek(int mid) {
	int k=0,ll=0;
	for(int i=1; i<=n; i++) {
		if(a[i]-ll<mid) {
			k++;
		} else {
			ll=a[i];
		}
	}
	if(k>m) {
		return 0;
	} else {
		return 1;
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>gl>>n>>m;
	for(int i=1; i<=n; i++) {
		cin>>a[i];
	}
	l=0;
	r=gl;
	int mid;
	while(l<r) {
		mid=(l+r)>>1;
		if(cheek(mid)) {
			l=mid+1;
		} else {
			r=mid-1;
		}
	}
	if(!cheek(l)) {
		l--;
	}
	cout<<l;
	return 0;
}

